class Solution:
    def checkInclusion(self, s1, s2):
        L = len(s1)
        if L > len(s2):
            return False
        need = [0] * 26
        win = [0] * 26
        a = ord('a')
        for c in s1:
            need[ord(c) - a] += 1
        for i in range(L):
            win[ord(s2[i]) - a] += 1
        if win == need:
            return True
        for i in range(L, len(s2)):
            win[ord(s2[i]) - a] += 1
            win[ord(s2[i - L]) - a] -= 1
            if win == need:
                return True
        return False

