var checkInclusion = function(s1, s2) {
    const L = s1.length;
    if (L > s2.length) return false;
    const need = new Array(26).fill(0);
    const win = new Array(26).fill(0);
    const a = 'a'.charCodeAt(0);
    for (const c of s1) need[c.charCodeAt(0) - a]++;
    for (let i = 0; i < L; i++) win[s2.charCodeAt(i) - a]++;
    const match = () => { for (let i = 0; i < 26; i++) if (win[i] !== need[i]) return false; return true; };
    if (match()) return true;
    for (let i = L; i < s2.length; i++) {
        win[s2.charCodeAt(i) - a]++;
        win[s2.charCodeAt(i - L) - a]--;
        if (match()) return true;
    }
    return false;
};
